<?php if(!hasPermission('sales_read')){http_response_code(403); include __DIR__.'/../errors/403.php'; return;} $db=Database::connection(); $rows=$db->query("SELECT s.*,c.name customer FROM sales_invoices s LEFT JOIN customers c ON c.id=s.customer_id ORDER BY s.id DESC")->fetchAll(); ?>
<div class="container py-4"><h3>Sales Register</h3><a class="btn btn-success mb-3" href="<?=url('sales/create')?>">Create</a><table class="table"><tr><th>Invoice</th><th>Date</th><th>Customer</th><th>Total</th><th>Paid</th><th>Bal</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=$r['invoice_no']?></td><td><?=formatDate($r['invoice_date'])?></td><td><?=sanitize($r['customer'])?></td><td><?=formatIndianCurrency($r['total_amount'])?></td><td><?=formatIndianCurrency($r['paid_amount'])?></td><td><?=formatIndianCurrency($r['balance_amount'])?></td><td><a href="<?=url('sales/view/'.$r['id'])?>">View</a></td></tr><?php endforeach;?></table></div>
